# ---- Parameters ----
ANGLE = 360  # Revolve angle in degrees.
OUTPUT = "part_freecad.step"


doc = FreeCAD.newDocument("TopOpt")

edges = []
n = len(POINTS)
for i in range(n):
    p1 = FreeCAD.Vector(POINTS[i][0], POINTS[i][1], 0)
    p2 = FreeCAD.Vector(POINTS[(i+1)%n][0], POINTS[(i+1)%n][1], 0)
    edges.append(Part.makeLine(p1, p2))

wire = Part.Wire(edges)
face = Part.Face(wire)

# Revolve around the y-axis from (0, 0, 0) to (0, 1, 0).
solid = face.revolve(
    FreeCAD.Vector(0, 0, 0),   # Revolve origin.
    FreeCAD.Vector(0, 1, 0),   # Revolve axis direction.
    ANGLE                       # Angle in degrees.
)

# Export STEP.
solid.exportStep(OUTPUT)
print(f"FreeCAD STEP exported: {OUTPUT}")
